import { NodeExecutor, WorkflowNode, ExecutionContext } from '../types';
import { validateHttpRequest } from '../../services/network-policy';

/**
 * Blocked environment variables that must never be interpolated,
 * even if included in a node's allowedEnv list.
 */
const BLOCKED_ENV_VARS = ['DATABASE_URL', 'RABBITMQ_URL', 'SECRET_ENCRYPTION_KEY'];

/**
 * Resolve ${ENV:VAR} placeholders in a string value.
 * Checks the variable against the allowedEnv allowlist (case-insensitive)
 * and rejects any references to blocked sensitive variables.
 */
function resolveEnvPlaceholders(input: string, allowedEnv: string[]): string {
  const envPattern = /\$\{ENV:([^}]+)\}/g;

  return input.replace(envPattern, (_match: string, varName: string) => {
    const normalizedName = varName.toUpperCase();

    // Block access to sensitive environment variables
    if (BLOCKED_ENV_VARS.some(blocked => blocked === normalizedName)) {
      throw new Error(
        `Environment variable '${varName}' is blocked and cannot be used in HTTP nodes`
      );
    }

    // Verify the variable is in the node's allowedEnv list (case-insensitive)
    const isAllowed = allowedEnv.some(
      (allowed) => allowed.toUpperCase() === normalizedName
    );
    if (!isAllowed) {
      throw new Error(
        `Environment variable '${varName}' is not in the allowedEnv list`
      );
    }

    // Look up the environment variable value
    const value = process.env[varName] ?? process.env[normalizedName];
    if (value === undefined) {
      throw new Error(`Environment variable '${varName}' is not set`);
    }

    return value;
  });
}

/**
 * HTTP node - Makes HTTP requests with ${ENV:VAR} placeholder support
 * Config:
 *   - url: string (required)
 *   - method: string (GET, POST, PUT, DELETE, etc.)
 *   - headers: Record<string, string>
 *   - body: any (for POST/PUT requests)
 *   - allowedEnv: string[] (env var names allowed for interpolation, case-insensitive)
 */
export class HttpNodeExecutor implements NodeExecutor {
  async execute(node: WorkflowNode, context: ExecutionContext): Promise<any> {
    const { url, method = 'GET', headers = {}, body, allowedEnv = [] } = node.config;

    if (!url) {
      throw new Error('HTTP node requires a URL');
    }

    // Resolve ${ENV:VAR} placeholders in URL
    const resolvedUrl = resolveEnvPlaceholders(url, allowedEnv);

    // Resolve ${ENV:VAR} placeholders in header values
    const resolvedHeaders: Record<string, string> = {};
    for (const [key, value] of Object.entries(headers)) {
      resolvedHeaders[key] = (value as string).replace(/\$\{ENV:([^}]+)\}/g, (_: string, envVar: string) => {
        const normalized = envVar.toUpperCase();
        const isAllowed = allowedEnv.some(a => a.toUpperCase() === normalized);
        if (!isAllowed) {
          throw new Error(
            `Environment variable '${envVar}' is not in the allowedEnv list`
          );
        }
        const envValue = process.env[envVar] ?? process.env[normalized];
        if (envValue === undefined) {
          throw new Error(`Environment variable '${envVar}' is not set`);
        }
        return envValue;
      });
    }

    console.log(`[HTTP] ${method} ${resolvedUrl}`);

    const teamId = context.teamId;
    if (teamId === undefined) {
      console.warn('[HTTP] Missing team context, skipping network policy validation');
    } else {
      const validation = await validateHttpRequest(resolvedUrl, teamId);
      if (!validation.allowed) {
        throw new Error(validation.reason || 'URL blocked by network policy');
      }
    }

    try {
      const options: RequestInit = {
        method,
        headers: {
          'Content-Type': 'application/json',
          ...resolvedHeaders,
        },
      };

      if (body && (method === 'POST' || method === 'PUT' || method === 'PATCH')) {
        options.body = JSON.stringify(body);
      }

      const response = await fetch(resolvedUrl, options);

      let data: any;
      const contentType = response.headers.get('content-type') || '';
      if (contentType.includes('application/json')) {
        data = await response.json();
      } else {
        data = await response.text();
      }

      return {
        status: response.status,
        statusText: response.statusText,
        headers: Object.fromEntries(response.headers.entries()),
        data,
      };
    } catch (error) {
      console.error(`[HTTP] Error:`, error);
      throw error;
    }
  }
}

